"use strict";parserFactory.register("lightnovelbastion.com",()=>new LightNovelBastionParser);class LightNovelBastionParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.listing-chapters_wrap");return util.hyperlinksToChapterList(t).reverse()}findContent(e){return e.querySelector("div.reading-content")}findChapterTitle(e){return e.querySelector("ol.breadcrumb li.active").textContent}extractTitleImpl(e){let t=e.querySelector("div.post-title");return null!==t?(util.removeChildElementsMatchingSelector(t,"span"),t.textContent):null}extractAuthor(e){let t=e.querySelector("div.author-content");return null===t?super.extractAuthor(e):t.textContent}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"div.lnbad-tag"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary__content p:not(.zeno_font_resizer)")]}}